export const script = "\nfunction countUp(el){var t=+el.dataset.count,dur=1100,st=performance.now();\n  function tick(now){var p=Math.min((now-st)/dur,1);el.textContent=Math.floor(p*t).toLocaleString();if(p<1)requestAnimationFrame(tick);else el.textContent=t.toLocaleString();}\n  requestAnimationFrame(tick);}\nfunction enter(e){e.preventDefault();\n  document.getElementById('login').style.display='none';\n  document.getElementById('app').style.display='block';window.scrollTo(0,0);\n  document.querySelectorAll('[data-count]').forEach(countUp);\n  setTimeout(function(){document.querySelectorAll('.bar .col').forEach(function(c){c.style.transform='scaleY('+(c.dataset.h/100)+')'});},250);\n}\ndocument.querySelectorAll('.side a').forEach(function(a){a.onclick=function(){\n  document.querySelectorAll('.side a').forEach(function(x){x.classList.remove('on')});a.classList.add('on');}});\n\n;try{document.querySelectorAll('[data-count]').forEach(countUp);setTimeout(function(){document.querySelectorAll('.bar .col').forEach(function(c){c.style.transform='scaleY('+(c.dataset.h/100)+')'});},250);}catch(e){}";

